VALUES
  ('pukao-64311456-moex-00248', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依據就業保險法的規定，失業給付的請領條件為被保險人於非自願離職辦理退保當日前3年內，保 險年資合計滿1年以上，具有工作能力及繼續工作意願，向公立就業服務機構辦理求職登記，自求 職登記之日起幾日內仍無法推介就業或安排職業訓練，才可請領？', '["30日", "16日", "15日", "14日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00249', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '根據公益勸募條例的規定，如果勸募活動所得在新臺幣1千萬元以下者，勸募團體辦理勸募活動之 必要支出，得動用勸募活動所得的多少百分比來作支應？', '["百分之十五", "百分之二十", "百分之二十五", "百分之十"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00250', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '精神衛生法修法於民國111年11月29日完成三讀，由總統修正公布，2年之後正式施行。此次修法 有幾項重要改革，下列何者並不符合此次修法精神？', '["緊急安置期間為7日，並應注意嚴重病人權益之保護及進行必要之治療；強制鑑定，應自緊急安 置之次日起3日內完成", "針對精神照護機構限制病人居住和行動等措施，「需經病人同意」並應在「最小限制」內施行。 若因醫療需要或在緊急狀況下，則可在「告知病人後」進行", "當精神病人急性發病，出現自傷或傷害他人的行為卻拒絕住院時，政府依法可以指定醫院「緊 急安置」病人，並強制進行精神鑑定。若鑑定結果需全日治療，醫院應向審查會申請許可，將 病人強制住院", "精神病人從醫院出院到社區期間，應協助連結醫療、精神復健、就學、就養、就業等服務，並 以多元化、可選擇且服務不中斷為原則，讓病人生活在社區能獲得足夠的支持"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00251', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '政府為落實聯合國公民與政治權利國際公約、經濟社會文化權利國際公約、消除對婦女一切形式 歧視公約、兒童權利公約及身心障礙者權利公約，分別制定施行法，並明定須定期提出國家報告。 請問下列那一個公約施行法明定，每5年提出國家報告？', '["兒童權利公約施行法", "消除對婦女一切形式歧視公約施行法", "身心障礙者權利公約施行法", "公民與政治權利國際公約及經濟社會文化權利國際公約施行法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00252', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '社會救助法第5條之3明定，本法所稱有工作能力，指16歲以上，未滿65歲者；但有7款排除條件可 不適用有工作能力者。請問下述那個條件不在此7款中？', '["20歲以下仍在國內就讀空中大學、大學院校以上進修學校、在職班、學分班、僅於夜間或假日 上課、遠距教學以外學校，致不能工作", "因照顧特定身心障礙或罹患特定病症且不能自理生活之共同生活或受扶養親屬，致不能工作", "婦女懷胎6個月以上至分娩後2個月內，致不能工作；或懷胎期間經醫師診斷不宜工作", "獨自扶養6歲以下之直系血親卑親屬致不能工作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00253', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '有關特殊境遇家庭扶助條例的各項補助條件、給付金額與給付期間等規定，下列何者錯誤？', '["子女生活津貼之核發標準，每一名子女或孫子女每月補助當年度最低工資之十分之一，每年申 請一次", "符合規定申請緊急生活扶助者，按當年度低收入戶每人每月最低生活費用標準一倍核發，每人 每次以補助6個月為原則，同一個案同一事由以補助兩次為限", "直轄市、縣（市）主管機關應於緊急生活扶助核准後，定期派員訪視其生活情形；其生活已有 明顯改善者，應即停止扶助", "傷病醫療補助標準，本人及6歲以上未滿18歲之子女或孫子女，自行負擔醫療費用超過新臺幣3 萬元之部分，最高補助百分之七十，每人每年最高補助新臺幣12萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00254', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '為保障遭遇職業災害勞工及其家屬之生活，加強職業災害預防及職業災害勞工重建，於民國111年 5月1日正式施行勞工職業災害保險及保護法。下列有關該法的敘述，何者錯誤？', '["目的在藉由制定專法，整合勞工保險條例的職業災害保險，以及職業災害勞工保護法的規定， 以促進社會安全", "被保險人若遭遇職業傷病事故，得請領醫療、傷病、失能、死亡及失蹤等保險給付", "擴大納保範圍，將受僱登記有案事業單位勞工，不論僱用人數全部強制納保", "實際從事勞動之雇主、高級中等學校建教合作實施及建教生權益保障法規定之建教生，屬於自 願加保對象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00255', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '下列有關我國社會保險的敘述，何者錯誤？', '["勞工保險係屬社會保險，其財務處理方式採取「部分提存準備制」", "就業保險是我國社會保險中，唯一一個依據個別風險而單一化的保險項目", "開辦國民年金之目的在於，為無法參加任何社會保險之國人所設計，以補足社會安全體系的制 度缺口", "公教人員保險之財務處理方式採行「完全提存準備制」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00256', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '下列有關保險給付或津貼之描述，何者錯誤？', '["國民年金保險提供老年年金、身心障礙年金、遺屬年金、生育給付與喪葬給付", "農民健康保險給予生育給付、醫療給付、身心障礙給付及老年津貼", "就業保險之給付包括失業給付、提早就業獎助津貼、職業訓練生活津貼、育嬰留職停薪津貼、 失業被保險人及其眷屬全民健康保險保險費補助", "公教人員保險的保險給付為失能給付、養老給付、死亡給付、眷屬喪葬津貼、生育及育嬰留職 停薪津貼"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00257', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '按國民年金法之規定，中央主管機關依法應補助之保險費及應負擔之款項，下列何者不是法定的 籌措來源？', '["供國民年金之用之公益彩券盈餘", "調增營業稅徵收率百分之一", "基本保證年金由中央主管機關編列預算支應", "調增營利事業所得稅百分之零點五"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL)
